import React from 'react';
import './index.css';
import Image from './phonk_wallpaper.jpg';
import Header from './header.js';
import Footer from './footer.js';

let flag = false
let counter = 0

function MouseOver() {
    flag = true
    root.render(<MainPage />)
  }
  
  function MouseOut() {
    flag = false
    root.render(<MainPage />)
  }

function MainPage() {
    return(
    <div id="main_page">
      <Header />
      <div id="content">
        <div id="news" onMouseOver={MouseOver} onMouseOut={MouseOut}>
          <p class="name_card">Новости</p>
          <div id="news_place">
          </div>
        </div>
        <div id="game_shop" class="game_item_shop_card">
          <p class="name_card">Магазин</p>
          <img src={Image} alt="Хаха"/>
        </div>
        <div id="item_store" class="game_item_shop_card">
          <p class="name_card">Торговая площадка</p>
          <img src={Image} alt="Хаха"></img>
        </div>
      </div>
      <Footer />
    </div>
    )
  }
  

export default MainPage;
